from flask import Flask, render_template, request
import os

app = Flask(__name__)

def load_data(filename):
    """Load data from a text file in the data directory."""
    path = os.path.join('data', filename)
    data = []
    if os.path.isfile(path):
        with open(path, 'r') as file:
            for line in file:
                line = line.strip()
                if line:
                    data.append(line.split(','))
    return data

@app.route('/')
def index():
    categories = load_data('categories.txt')
    items = load_data('items.txt')
    offers = load_data('offers.txt')
    return render_template('index.html', categories=categories, items=items, offers=offers)

@app.route('/add_offer', methods=['POST'])
def add_offer():
    item_id = request.form.get('item_id')
    user_name = request.form.get('user_name')
    offer_amount = request.form.get('offer_amount')

    if not (item_id and user_name and offer_amount):
        return "Missing data", 400

    try:
        offer_amount_float = float(offer_amount)
    except ValueError:
        return "Invalid offer amount", 400

    # Load current offers
    offers = load_data('offers.txt')

    # Find offers for this item to enforce higher bid
    item_offers = [float(offer[2]) for offer in offers if offer[0] == item_id]

    if item_offers and offer_amount_float <= max(item_offers):
        return "Offer amount must be higher than existing offers", 400

    # Append new offer
    with open(os.path.join('data', 'offers.txt'), 'a') as f:
        f.write(f"{item_id},{user_name},{offer_amount}\n")

    return "Offer added successfully", 200

if __name__ == '__main__':
    app.run(debug=True)

